```class Solution {
public:
    long long maxGCDScore(vector<int>& nums, int k) {
        int n = nums.size();
        vector<int> dp(n + 1, 0);
        for (int i = 1; i <= n; i++) {
            dp[i] = dp[i - 1] + nums[i - 1];
        }
        long long res = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = i; j <= n; j++) {
                long long gcd = 1;
                for (int x : vector<int>(nums.begin() + i - 1, nums.begin() + j)) {
                    gcd = __gcd(gcd, x);
                }
                if (j - i + 1 <= k) {
                    res = max(res, (long long)gcd * (j - i + 1));
                }
            }
        }
        return res;
    }
};```
